// // This module is designed to hold a 4-bit input value and provide an output reflecting the current value stored in the register. It includes a 'load' control signal for loading data from the input and a 'clear' signal for resetting the register value to zero.
module top_module(input [3:0] in, input load, input clear, output [3:0] out);reg [3:0] reg_out;

  always @(*) begin
    if (clear) begin
      reg_out = 0;
    end else if (load) begin
      reg_out = in;
    end
  end

  assign out = reg_out;
endmodule
